17	#include "src/fastertransformer/layers/FfnLayer.h"
18	#include "src/fastertransformer/kernels/transpose_int8_kernels.h"
19	#include "src/fastertransformer/utils/nvtx_utils.h"
20	
21	namespace fastertransformer {
22	
23	template<typename T>
24	void FfnLayer<T>::forward(std::vector<fastertransformer::Tensor>*       output_tensors,
25	                          const std::vector<fastertransformer::Tensor>* input_tensors,
26	                          const FfnWeight<T>*                           ffn_weights)
27	{
28	    TensorMap input_tensor({{"ffn_input", input_tensors->at(0)}});
29	    TensorMap output_tensor({{"ffn_output", output_tensors->at(0)}});
30	    forward(&output_tensor, &input_tensor, ffn_weights);
31	}
32	
33	template<typename T>
34	void FfnLayer<T>::forward(TensorMap* output_tensors, TensorMap* input_tensors, const FfnWeight<T>* ffn_weights)
35	{
36	    // input tensors:
37	    //      ffn_input [token_num, hidden_dimension],
38	    //      ia3_tasks [batch_size] (optional)
39	    //      moe_k     [1], uint64 (optional)
40	    //      padding_offset [token_num] (optional)
41	    //      seq_len [1], int32, (optional), only used for ia3
42	
43	    // output tensors:
44	    //      ffn_output [token_num, hidden_dimension] or [moe_k * token_num, hidden_dimension] if use_moe
45	    //      expert_scales [token_num, moe_k] (optional)
46	    //      expanded_source_row_to_expanded_dest_row [token_num, moe_k] (optional)
47	    //      expert_for_source_row [token_num, moe_k] (optional)
48	
49	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
50	    FT_CHECK(input_tensors->size() >= 1 && input_tensors->size() <= 5);
51	    FT_CHECK(output_tensors->size() >= 1 || output_tensors->size() <= 4);
52	    bool   use_moe = false;
53	    size_t moe_k   = 0;
54	    if (input_tensors->isExist("moe_k")) {
55	        use_moe = true;
56	        moe_k   = input_tensors->at("moe_k").getVal<size_t>();
57	    }
58	    allocateBuffer(input_tensors->at("ffn_input").shape[0], moe_k, use_moe);
59	
60	    const int m             = input_tensors->at("ffn_input").shape[0];
61	    T*        output_tensor = output_tensors->at("ffn_output").getPtr<T>();
62	    const T*  input_tensor  = input_tensors->at("ffn_input").getPtr<const T>();
63	
64	    // for moe output
65	    T*   expert_scales    = nullptr;
66	    int* permuted_rows    = nullptr;
67	    int* permuted_experts = nullptr;
68	
69	    // moe outputs should exist or not together
70	    FT_CHECK((use_moe && output_tensors->isExist("expert_scales")
71	              && output_tensors->isExist("expanded_source_row_to_expanded_dest_row")
72	              && output_tensors->isExist("expert_for_source_row"))
73	             || (!use_moe && !output_tensors->isExist("expert_scales")
74	                 && !output_tensors->isExist("expanded_source_row_to_expanded_dest_row")
75	                 && !output_tensors->isExist("expert_for_source_row")));
76	
77	    if (use_moe) {
78	        expert_scales    = output_tensors->at("expert_scales").getPtr<T>();
79	        permuted_rows    = output_tensors->at("expanded_source_row_to_expanded_dest_row").getPtr<int>();
80	        permuted_experts = output_tensors->at("expert_for_source_row").getPtr<int>();
81	    }
82	
83	    // TODO: INT8 and Sparsity are currently not implemented (geglu or reglu)
84	    const bool use_gated_activation = use_gated_activation_ && ffn_weights->intermediate_weight2.kernel != nullptr;
85	
86	    // moe can't be used with use_gated_activation currently
87	    FT_CHECK(!(use_gated_activation && use_moe));
88	    auto activation_type = getActivationType();
89	
90	    const int* ia3_tasks = input_tensors->getPtr<const int>("ia3_tasks", nullptr);
91	
92	    if (use_moe) {
93	        PUSH_RANGE("FFN moe");
94	        FT_CHECK(ia3_tasks == nullptr);
95	        cublas_wrapper_->Gemm(CUBLAS_OP_N,
96	                              CUBLAS_OP_N,
97	                              expert_num_,
98	                              m,
99	                              hidden_units_,
100	                              ffn_weights->gating_weight.kernel,
101	                              expert_num_,
102	                              input_tensor,
103	                              hidden_units_,
104	                              moe_gates_buf_,
105	                              expert_num_);
106	
107	        if (int8_mode_ == 0) {
108	            moe_fc_runner_->run_moe_fc(input_tensor,
109	                                       moe_gates_buf_,
110	                                       ffn_weights->intermediate_weight.kernel,
111	                                       ffn_weights->intermediate_weight.weight_only_quant_scale,
112	                                       ffn_weights->intermediate_weight.bias,
113	                                       activation_type,
114	                                       ffn_weights->output_weight.kernel,
115	                                       ffn_weights->output_weight.weight_only_quant_scale,
116	                                       m,
117	                                       hidden_units_,
118	                                       inter_size_,
119	                                       expert_num_,
120	                                       moe_k,
121	                                       moe_fc_workspace_,
122	                                       output_tensor,
123	                                       expert_scales,
124	                                       permuted_rows,
125	                                       permuted_experts,
126	                                       stream_);
127	        }
128	        else if (int8_mode_ == 1) {
129	            FT_CHECK_WITH_INFO(moe_int8_weight_only_fc_runner_.get() != NULL,
130	                               "weight only runner was not initialized.");
131	
132	            FT_CHECK(ffn_weights->intermediate_weight.int8_kernel != NULL
133	                     && ffn_weights->intermediate_weight.weight_only_quant_scale != NULL);
134	
135	            FT_CHECK(ffn_weights->output_weight.int8_kernel != NULL
136	                     && ffn_weights->output_weight.weight_only_quant_scale != NULL);
137	
138	            moe_int8_weight_only_fc_runner_->run_moe_fc(
139	                input_tensor,
140	                moe_gates_buf_,
141	                reinterpret_cast<const uint8_t*>(ffn_weights->intermediate_weight.int8_kernel),
142	                ffn_weights->intermediate_weight.weight_only_quant_scale,
143	                ffn_weights->intermediate_weight.bias,
144	                activation_type,
145	                reinterpret_cast<const uint8_t*>(ffn_weights->output_weight.int8_kernel),
146	                ffn_weights->output_weight.weight_only_quant_scale,
147	                m,
148	                hidden_units_,
149	                inter_size_,
150	                expert_num_,
151	                moe_k,
152	                moe_fc_workspace_,
153	                output_tensor,
154	                expert_scales,
155	                permuted_rows,
156	                permuted_experts,
157	                stream_);
158	        }
159	        else {
160	            FT_CHECK_WITH_INFO(false, "Invalid int8 mode for MoE");
161	        }
162	
163	        sync_check_cuda_error();
164	        if (is_free_buffer_after_forward_ == true) {
165	            freeBuffer();
166	        }
167	        sync_check_cuda_error();
168	        POP_RANGE;
169	        return;
170	    }
171	
172	    PUSH_RANGE("FFN gemm 1");
173	    int m_tmp = input_tensors->at("ffn_input").shape[0];
174	    if (m_tmp % 8 != 0) {
175	        m_tmp = (m_tmp / 8 + 1) * 8;
176	    }
177	    const int m_padded = m_tmp;
178	#ifdef SPARSITY_ENABLED
179	    bool use_sparse_gemm = sparse_ && cublas_wrapper_->isUseSparse(1, inter_size_, m, hidden_units_);
180	#else
181	    constexpr bool use_sparse_gemm = false;
182	#endif
183	
184	    if (use_sparse_gemm) {
185	        FT_CHECK(!use_gated_activation);
186	#ifdef SPARSITY_ENABLED
187	        cublas_wrapper_->SpGemm(CUBLAS_OP_N,
188	                                CUBLAS_OP_N,
189	                                inter_size_,
190	                                m_padded,
191	                                hidden_units_,
192	                                ffn_weights->intermediate_weight.sp_kernel,
193	                                input_tensor,
194	                                inter_buf_);
195	#endif
196	    }
197	    else {
198	        if (int8_mode_ == 1) {
199	            FT_CHECK_WITH_INFO(weight_only_int8_fc_runner_.get() != NULL, "weight only runner was not initialized.");
200	            FT_CHECK(ffn_weights->intermediate_weight.int8_kernel != NULL
201	                     && ffn_weights->intermediate_weight.weight_only_quant_scale != NULL);
202	
203	            if (ia3_tasks == nullptr && !use_gated_activation) {
204	                // launch fused GEMM + activation
205	                weight_only_int8_fc_runner_->gemm_bias_act(
206	                    input_tensor,
207	                    reinterpret_cast<const uint8_t*>(ffn_weights->intermediate_weight.int8_kernel),
208	                    ffn_weights->intermediate_weight.weight_only_quant_scale,
209	                    ffn_weights->intermediate_weight.bias,
210	                    inter_buf_,
211	                    m,
212	                    inter_size_,
213	                    hidden_units_,
214	                    activation_type,
215	                    mixed_gemm_workspace_,
216	                    mixed_gemm_ws_bytes_,
217	                    stream_);
218	            }
219	            else {
220	                // Otherwise, let FT handle activation
221	                weight_only_int8_fc_runner_->gemm(
222	                    input_tensor,
223	                    reinterpret_cast<const uint8_t*>(ffn_weights->intermediate_weight.int8_kernel),
224	                    ffn_weights->intermediate_weight.weight_only_quant_scale,
225	                    inter_buf_,
226	                    m,
227	                    inter_size_,
228	                    hidden_units_,
229	                    mixed_gemm_workspace_,
230	                    mixed_gemm_ws_bytes_,
231	                    stream_);
232	
233	                if (use_gated_activation) {
234	                    FT_CHECK(ffn_weights->intermediate_weight2.int8_kernel != NULL
235	                             && ffn_weights->intermediate_weight2.weight_only_quant_scale != NULL);
236	
237	                    weight_only_int8_fc_runner_->gemm(
238	                        input_tensor,
239	                        reinterpret_cast<const uint8_t*>(ffn_weights->intermediate_weight2.int8_kernel),
240	                        ffn_weights->intermediate_weight2.weight_only_quant_scale,
241	                        inter_buf_2_,
242	                        m,
243	                        inter_size_,
244	                        hidden_units_,
245	                        mixed_gemm_workspace_,
246	                        mixed_gemm_ws_bytes_,
247	                        stream_);
248	                }
249	            }
250	        }
251	        else if (int8_mode_ == 2) {
252	            FT_CHECK(!use_gated_activation);
253	            cublas_wrapper_->Int8Gemm(inter_size_,
254	                                      m,
255	                                      hidden_units_,
256	                                      ffn_weights->intermediate_weight.int8_kernel,
257	                                      hidden_units_,
258	                                      input_tensors->getPtr<int8_t>("ffn_input"),
259	                                      hidden_units_,
260	                                      reinterpret_cast<int8_t*>(inter_buf_),
261	                                      inter_size_,
262	                                      ffn_weights->intermediate_weight.scale_inter);
263	        }
264	        else {
265	            cublas_wrapper_->Gemm(CUBLAS_OP_N,
266	                                  CUBLAS_OP_N,
267	                                  inter_size_,
268	                                  m,
269	                                  hidden_units_,
270	                                  ffn_weights->intermediate_weight.kernel,
271	                                  inter_size_,
272	                                  input_tensor,
273	                                  hidden_units_,
274	                                  inter_buf_,
275	                                  inter_size_);
276	            if (use_gated_activation) {
277	                cublas_wrapper_->Gemm(CUBLAS_OP_N,
278	                                      CUBLAS_OP_N,
279	                                      inter_size_,
280	                                      m,
281	                                      hidden_units_,
282	                                      ffn_weights->intermediate_weight2.kernel,
283	                                      inter_size_,
284	                                      input_tensor,
285	                                      hidden_units_,
286	                                      inter_buf_2_,
287	                                      inter_size_);
288	            }
289	        }
290	    }
291	
292	    POP_RANGE;
293	
294	    if (int8_mode_ != 1 || ia3_tasks != nullptr || use_gated_activation) {
295	        // if int8_mode == 1 && ia3_tasks == nullptr && we don't use gated activations, we use cutlass
296	        // to fuse GEMM + bias + activation, so we skip the activation function here. In all
297	        // other cases, we must apply the activation function separately.
298	        PUSH_RANGE("add bias act");
299	        genericActivation(m,
300	                          ffn_weights->intermediate_weight.bias,
301	                          use_gated_activation ? ffn_weights->intermediate_weight2.bias : nullptr,
302	                          input_tensors->at("ia3_tasks", {MEMORY_GPU, TYPE_INT32, {}, nullptr}).getPtr<const int>(),
303	                          ffn_weights->ia3_weight.kernel,
304	                          int8_mode_ == 2 ? ffn_weights->intermediate_weight.scale_out : (float*)nullptr,
305	                          int8_mode_ == 2 ? ffn_weights->output_weight.scale : (float*)nullptr,
306	                          input_tensors->getPtr<int>("padding_offset", nullptr),
307	                          input_tensors->getVal<int>("seq_len", 1));
308	        POP_RANGE;
309	    }
310	
311	    sync_check_cuda_error();
312	
313	    PUSH_RANGE("FFN gemm 2");
314	#ifdef SPARSITY_ENABLED
315	    use_sparse_gemm = sparse_ && cublas_wrapper_->isUseSparse(1, hidden_units_, m, inter_size_);
316	#endif
317	    if (use_sparse_gemm) {
318	#ifdef SPARSITY_ENABLED
319	        cublas_wrapper_->SpGemm(CUBLAS_OP_N,
320	                                CUBLAS_OP_N,
321	                                hidden_units_,
322	                                m_padded,
323	                                inter_size_,
324	                                ffn_weights->output_weight.sp_kernel,
325	                                inter_buf_,
326	                                output_tensor);
327	#endif
328	    }
329	    else {
330	        if (int8_mode_ == 1) {
331	            FT_CHECK_WITH_INFO(weight_only_int8_fc_runner_.get() != NULL, "weight only runner was not initialized.");
332	            FT_CHECK(ffn_weights->output_weight.int8_kernel != NULL
333	                     && ffn_weights->output_weight.weight_only_quant_scale != NULL);
334	            weight_only_int8_fc_runner_->gemm(inter_buf_,
335	                                              reinterpret_cast<const uint8_t*>(ffn_weights->output_weight.int8_kernel),
336	                                              ffn_weights->output_weight.weight_only_quant_scale,
337	                                              output_tensor,
338	                                              m,
339	                                              hidden_units_,
340	                                              inter_size_,
341	                                              mixed_gemm_workspace_,
342	                                              mixed_gemm_ws_bytes_,
343	                                              stream_);
344	        }
345	        else if (int8_mode_ == 2) {
346	            int8_fc_runner_->gemm(reinterpret_cast<int8_t*>(inter_buf_),
347	                                  ffn_weights->output_weight.int8_kernel,
348	                                  QuantMode::PerTensorQuant,
349	                                  ffn_weights->output_weight.scale_inter,
350	                                  ffn_weights->output_weight.scale_out,
351	                                  output_tensors->getPtr<T>("ffn_output"),
352	                                  m,
353	                                  hidden_units_,
354	                                  inter_size_,
355	                                  nullptr,
356	                                  0,
357	                                  stream_);
358	        }
359	        else {
360	            cublas_wrapper_->Gemm(CUBLAS_OP_N,
361	                                  CUBLAS_OP_N,
362	                                  hidden_units_,
363	                                  m,
364	                                  inter_size_,
365	                                  ffn_weights->output_weight.kernel,
366	                                  hidden_units_,
367	                                  inter_buf_,
368	                                  inter_size_,
369	                                  output_tensor,
370	                                  hidden_units_);
371	        }
372	    }
373	    sync_check_cuda_error();
374	    POP_RANGE;
375	
376	    if (is_free_buffer_after_forward_ == true) {
377	        freeBuffer();
378	    }
379	    sync_check_cuda_error();
380	}
