452	template<typename T>
453	void FfnLayer<T>::allocateBuffer()
454	{
455	    FT_CHECK_WITH_INFO(false,
456	                       "FfnLayer::allocateBuffer() is deprecated. Use `allocateBuffer(size_t token_num, ...)` instead");
457	}
458	
459	template<typename T>
460	void FfnLayer<T>::allocateBuffer(size_t token_num, int moe_k, bool use_moe)
461	{
462	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
463	    if (use_moe) {
464	        moe_gates_buf_ =
465	            (T*)allocator_->reMalloc(moe_gates_buf_, sizeof(T) * pad_to_multiple_of_16(token_num * expert_num_), false);
466	        size_t ws_size_moe = 0;
467	        if (int8_mode_ == 0) {
468	            FT_CHECK_WITH_INFO(moe_fc_runner_.get() != NULL, "moe runner was not initialized.");
469	            ws_size_moe = moe_fc_runner_->getWorkspaceSize(token_num, hidden_units_, inter_size_, expert_num_, moe_k);
470	        }
471	        else if (int8_mode_ == 1) {
472	            FT_CHECK_WITH_INFO(moe_int8_weight_only_fc_runner_.get() != NULL,
473	                               "weight only moe runner was not initialized.");
474	            ws_size_moe = moe_int8_weight_only_fc_runner_->getWorkspaceSize(
475	                token_num, hidden_units_, inter_size_, expert_num_, moe_k);
476	        }
477	
478	        moe_fc_workspace_ = (char*)allocator_->reMalloc(moe_fc_workspace_, sizeof(char) * ws_size_moe, false);
479	    }
480	    else {
481	        const auto type_size = int8_mode_ == 2 ? sizeof(int8_t) : sizeof(T);
482	        inter_buf_           = (T*)allocator_->reMalloc(inter_buf_, type_size * token_num * max_inter_size_, false);
483	        if (use_gated_activation_) {
484	            inter_buf_2_ = (T*)allocator_->reMalloc(inter_buf_2_, sizeof(T) * token_num * max_inter_size_, false);
485	        }
486	
487	        if (int8_mode_ == 1) {
488	            FT_CHECK_WITH_INFO(weight_only_int8_fc_runner_.get() != NULL, "weight only runner was not initialized.");
489	            // We use max_size for n and k since we reuse buffers for both FCs and want to allocate the max
490	            // possible memory that would be required by any of the individual gemms.
491	            const int max_size    = std::max(hidden_units_, inter_size_);
492	            mixed_gemm_ws_bytes_  = weight_only_int8_fc_runner_->getWorkspaceSize(token_num, max_size, max_size);
493	            mixed_gemm_workspace_ = (char*)allocator_->reMalloc(mixed_gemm_workspace_, mixed_gemm_ws_bytes_, false);
494	        }
495	        else if (int8_mode_ == 2) {
496	            const int max_size   = std::max(hidden_units_, inter_size_);
497	            int8_gemm_ws_bytes_  = int8_fc_runner_->getWorkspaceSize(token_num, max_size, max_size);
498	            int8_gemm_workspace_ = (char*)allocator_->reMalloc(int8_gemm_workspace_, int8_gemm_ws_bytes_, false);
499	        }
500	    }
501	
502	    is_allocate_buffer_ = true;
503	}
504	
505	template<typename T>
506	void FfnLayer<T>::freeBuffer()
507	{
508	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
509	    if (is_allocate_buffer_) {
510	        allocator_->free((void**)(&inter_buf_));
511	        if (use_gated_activation_) {
512	            allocator_->free((void**)(&inter_buf_2_));
513	        }
514	        if (expert_num_ != 0) {
515	            allocator_->free((void**)(&moe_gates_buf_));
516	            allocator_->free((void**)(&moe_fc_workspace_));
517	        }
518	
519	        if (mixed_gemm_workspace_) {
520	            allocator_->free((void**)(&mixed_gemm_workspace_));
521	            mixed_gemm_ws_bytes_ = 0;
522	        }
523	
524	        is_allocate_buffer_ = false;
525	    }
526	}
