528	#define INVOKE_GENERIC_ACT(ACT)                                                                                        \
529	    invokeGenericActivation<ACT>(inter_buf_,                                                                           \
530	                                 bias1,                                                                                \
531	                                 inter_buf_2_,                                                                         \
532	                                 bias2,                                                                                \
533	                                 ia3_tasks,                                                                            \
534	                                 ia3_weights,                                                                          \
535	                                 m,                                                                                    \
536	                                 inter_size_,                                                                          \
537	                                 int8_mode_,                                                                           \
538	                                 activation_in,                                                                        \
539	                                 activation_out,                                                                       \
540	                                 padding_offset,                                                                       \
541	                                 seq_len,                                                                              \
542	                                 stream_);
543	
544	template<typename T>
545	void FfnLayer<T>::genericActivation(int          m,
546	                                    const T*     bias1,
547	                                    const T*     bias2,
548	                                    const int*   ia3_tasks,
549	                                    const T*     ia3_weights,
550	                                    const float* activation_in,
551	                                    const float* activation_out,
552	                                    const int*   padding_offset,
553	                                    const int    seq_len)
554	{
555	    if (ia3_tasks != nullptr) {
556	        FT_CHECK(seq_len > 0);
557	    }
558	
559	    // dispatch according to actual activation
560	    switch (getActivationType()) {
561	        case ActivationType::Gelu:
562	        case ActivationType::GeGLU:
563	            if (inter_buf_2_ == nullptr && int8_mode_ <= 1) {
564	                invokeAddBiasGeluV2(
565	                    inter_buf_, bias1, ia3_tasks, ia3_weights, padding_offset, seq_len, m, inter_size_, stream_);
566	            }
567	            else {
568	                INVOKE_GENERIC_ACT(GeluActivation);
569	            }
570	            break;
571	        case ActivationType::Relu:
572	        case ActivationType::ReGLU:
573	            INVOKE_GENERIC_ACT(ReluActivation);
574	            break;
575	        case ActivationType::Silu:
576	        case ActivationType::SiGLU:
577	            INVOKE_GENERIC_ACT(SiluActivation);
578	            break;
579	        case ActivationType::Identity:
580	            INVOKE_GENERIC_ACT(IdentityActivation);
581	            break;
582	    }
583	}
584	
585	#undef INVOKE_GENERIC_ACT
